private void traverseAndAddNames(Node node, BitSet gen, BitSet kill) {
  if (node == null) {
    return;
  }
  if (NodeUtil.isName(node)) {
    addToSetIfLocal(node, kill);
    addToSetIfLocal(node, gen);
  }
  for (Node child = node.getFirstChild(); child != null; child = child.getNext()) {
    traverseAndAddNames(child, gen, kill);
  }
}

