    addToSetIfLocal(n, gen);
    if (!conditional) {
      addToSetIfLocal(n, kill);
    }
  } else {
    for (Node c = n.getFirstChild(); c != null; c = c.getNext()) {
      handleComplexExpression(c, gen, kill, conditional);
    }
  }
}

